import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void singlePair() {
        assertEquals(1, new Solution().pairCount(new int[]{2, 7, 11, 15}, 9));
    }

    @Test
    void allOnesTarget2() {
        assertEquals(6, new Solution().pairCount(new int[]{1, 1, 1, 1}, 2));
    }

    @Test
    void noPairs() {
        assertEquals(0, new Solution().pairCount(new int[]{1, 2, 3, 4, 5}, 100));
    }

    @Test
    void withNegatives() {
        assertEquals(2, new Solution().pairCount(new int[]{-1, 1, 0, 2, -2}, 0));
    }

    @Test
    void singletonNoPair() {
        assertEquals(0, new Solution().pairCount(new int[]{5}, 10));
    }
}
